export default function VocabLessonPage() {
  const params   = useParams()
  const id       = params.id as string
  const words    = LESSON_VOCAB[id] ?? VOCAB_L1_1

  const [idx,         setIdx]         = useState(0)
  const [flipped,     setFlipped]     = useState(false)
  const [known,       setKnown]       = useState<Set<number>>(new Set())
  const [review,      setReview]      = useState<Set<number>>(new Set())
  const [phase,       setPhase]       = useState<'cards' | 'review' | 'done'>('cards')
  const [reviewList,  setReviewList]  = useState<number[]>([])
  const [reviewIdx,   setReviewIdx]   = useState(0)
  const vocabXp = 30
  const savedRef = useRef(false)

  useEffect(() => {
    if (phase !== 'done' || savedRef.current) return
    savedRef.current = true
    async function saveVocabProgress() {
      try {
        const supabase = createEnglishClient()
        const { data: { session } } = await supabase.auth.getSession()
        const user = session?.user
        if (!user) return
        const { data: existing } = await supabase
          .from('english_lesson_progress')
          .select('completed')
          .eq('user_id', user.id)
          .eq('lesson_id', id)
          .maybeSingle()
        const alreadyDone = existing?.completed === true
        await supabase.from('english_lesson_progress').upsert({
          user_id:      user.id,
          lesson_id:    id,
          lesson_type:  'vocabulary',
          lesson_title: `Vocab ${id}`,
          completed:    true,
          score:        Math.round(known.size / words.length * 100),
          xp_earned:    vocabXp,
          completed_at: new Date().toISOString(),
        }, { onConflict: 'user_id,lesson_id' })
        if (!alreadyDone) {
          const { data: profile } = await supabase
            .from('english_user_profiles')
            .select('total_xp, current_streak, longest_streak, last_active_at')
            .eq('user_id', user.id).maybeSingle()
          const now = new Date()
          const lastActive = profile?.last_active_at ? new Date(profile.last_active_at) : null
          const isNewDay = !lastActive || now.toDateString() !== lastActive.toDateString()
          const newStreak = isNewDay ? (profile?.current_streak ?? 0) + 1 : (profile?.current_streak ?? 1)
          await supabase.from('english_user_profiles').upsert({
            user_id: user.id,
            total_xp: (profile?.total_xp ?? 0) + vocabXp,
            current_streak: newStreak,
            longest_streak: Math.max(newStreak, profile?.longest_streak ?? 0),
            last_active_at: now.toISOString(),
          }, { onConflict: 'user_id' })
        }
      } catch { /* silent */ }
    }
    saveVocabProgress()
  }, [phase, id, known, words])

  const word    = phase === 'review' ? words[reviewList[reviewIdx]] : words[idx]
  const total   = words.length
  const doneSet = known.size + review.size
  const progress = Math.round(doneSet / total * 100)

  function markKnown() {
    const next = new Set(known); next.add(idx)
    setKnown(next)
    advance(next.size + review.size, next)
  }

  function markReview() {
    const next = new Set(review); next.add(idx)
    setReview(next)
    advance(known.size + next.size, known, next)
  }

  function advance(done: number, _k = known, r = review) {
    setFlipped(false)
    if (done >= total) {
      const rl = Array.from(r)
      if (rl.length > 0) {
        setReviewList(rl); setReviewIdx(0); setPhase('review')
      } else {
        setPhase('done')
      }
    } else {
      setIdx(i => i + 1)
    }
  }

  function reviewKnown() {
    const next = new Set(review)
    next.delete(reviewList[reviewIdx])
    setReview(next)
    const rl = Array.from(next)
    setFlipped(false)
    if (reviewIdx + 1 < reviewList.length) {
      setReviewList(rl.length ? rl : [])
      setReviewIdx(i => i + 1)
    } else if (rl.length > 0) {
      setReviewList(rl); setReviewIdx(0)
    } else {
      setPhase('done')
    }
  }

  function reviewAgain() {
    setFlipped(false)
    if (reviewIdx + 1 < reviewList.length) {
      setReviewIdx(i => i + 1)
    } else {
      setReviewIdx(0)
    }
  }

  // ── Done screen ─────────────────────────────────────────────────
  if (phase === 'done') return (
    <div style={{ minHeight: '100vh', background: '#F4F6FA', fontFamily: "'Montserrat', sans-serif", display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 24 }}>
      <div style={{ maxWidth: 440, width: '100%', background: '#fff', borderRadius: 28, padding: '48px 36px', boxShadow: '0 8px 40px rgba(0,56,118,0.12)', textAlign: 'center', border: '1px solid rgba(0,56,118,0.07)' }}>
        <div style={{ fontSize: 60, marginBottom: 16 }}>🎉</div>
        <div style={{ fontSize: 12, color: MU, fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.12em', marginBottom: 8 }}>{t.vocab.all_done}</div>
        <div style={{ fontSize: 28, fontWeight: 900, color: N, marginBottom: 6, letterSpacing: '-0.02em' }}>{t.lesson.excellent}</div>
        <div style={{ fontSize: 14, color: MU, marginBottom: 32 }}>{total} {t.vocab.total}</div>
        <div style={{ display: 'flex', justifyContent: 'center', gap: 40, marginBottom: 32 }}>
          <div style={{ textAlign: 'center' }}>
            <div style={{ fontSize: 32, fontWeight: 900, color: T, lineHeight: 1 }}>{known.size}</div>
            <div style={{ fontSize: 11, color: MU, marginTop: 5, fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.07em' }}>{t.vocab.learned}</div>
          </div>
          <div style={{ textAlign: 'center' }}>
            <div style={{ fontSize: 32, fontWeight: 900, color: G, lineHeight: 1 }}>+{vocabXp}</div>
            <div style={{ fontSize: 11, color: MU, marginTop: 5, fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.07em' }}>{t.common.xp}</div>
          </div>
        </div>
        <div style={{ height: 8, background: '#F1F5F9', borderRadius: 99, overflow: 'hidden', marginBottom: 32 }}>
          <div style={{ height: '100%', width: '100%', background: `linear-gradient(90deg, ${T}, #34D399)`, borderRadius: 99 }} />
        </div>
        <div style={{ display: 'flex', gap: 10 }}>
          <button onClick={() => { setIdx(0); setFlipped(false); setKnown(new Set()); setReview(new Set()); setPhase('cards') }} style={{
            flex: 1, padding: 14, borderRadius: 12, border: '1.5px solid rgba(0,56,118,0.2)',
            background: '#fff', color: N, fontSize: 13, fontWeight: 700, cursor: 'pointer', fontFamily: 'inherit',
          }}>
            {t.lesson.retry}
          </button>
          <Link href={`/english/zku/student/lesson/${id}`} style={{
            flex: 2, padding: 14, borderRadius: 12, border: 'none',
            background: N, color: '#fff', fontSize: 13, fontWeight: 700,
            textDecoration: 'none', display: 'flex', alignItems: 'center',
            justifyContent: 'center', gap: 6, boxShadow: '0 4px 16px rgba(0,56,118,0.28)',
          }}>
            {t.lesson.back_to_module} <IcArrowRight size={14} color="#fff" />
          </Link>
        </div>
      </div>
    </div>
  )

  const isReviewPhase = phase === 'review'
  const _currentTotal = isReviewPhase ? reviewList.length : total
  const currentIdx    = isReviewPhase ? reviewIdx : idx

  return (
    <div style={{ minHeight: '100vh', background: '#F4F6FA', fontFamily: "'Montserrat', sans-serif" }}>

      {/* Header */}
      <div style={{ background: '#fff', borderBottom: '1px solid rgba(0,56,118,0.08)', padding: '0 24px', position: 'sticky', top: 0, zIndex: 10 }}>
        <div style={{ maxWidth: 600, margin: '0 auto', display: 'flex', alignItems: 'center', gap: 16, height: 60 }}>
          <Link href={`/english/zku/student/lesson/${id}`} style={{ color: MU, textDecoration: 'none', fontSize: 12, fontWeight: 600, flexShrink: 0 }}>
            ← {t.vocab.back_lesson}
          </Link>
          <div style={{ flex: 1 }}>
            <div style={{ height: 6, background: '#F1F5F9', borderRadius: 99, overflow: 'hidden' }}>
              <div style={{ height: '100%', width: `${isReviewPhase ? Math.round((reviewIdx + 1) / reviewList.length * 100) : progress}%`, background: isReviewPhase ? G : N, borderRadius: 99, transition: 'width 0.3s ease' }} />
            </div>
          </div>
          <div style={{ fontSize: 11, fontWeight: 700, color: isReviewPhase ? G : N, flexShrink: 0 }}>
            {isReviewPhase ? `${t.vocab.review ?? 'Повтор'}: ${reviewIdx + 1}/${reviewList.length}` : `${currentIdx + 1} / ${total}`}
          </div>
        </div>
      </div>

      <div style={{ maxWidth: 540, margin: '0 auto', padding: '32px 24px 48px' }}>

        {/* Phase label */}
        {isReviewPhase && (
          <div style={{ textAlign: 'center', marginBottom: 16 }}>
            <span style={{ fontSize: 11, fontWeight: 700, color: G, background: '#FEF3C7', padding: '5px 14px', borderRadius: 99, border: '1px solid #FCD34D', textTransform: 'uppercase', letterSpacing: '0.08em' }}>
              {t.vocab.review}
            </span>
          </div>
        )}

        {/* Flashcard */}
        <div
          onClick={() => setFlipped(f => !f)}
          style={{
            background: '#fff', borderRadius: 24, minHeight: 320,
            boxShadow: '0 4px 32px rgba(0,56,118,0.1)', border: '1px solid rgba(0,56,118,0.07)',
            cursor: 'pointer', marginBottom: 16, padding: '36px 32px',
            display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
            transition: 'box-shadow 0.2s',
            userSelect: 'none',
          }}
        >
          {!flipped ? (
            /* Front: word */
            <div style={{ textAlign: 'center' }}>
              <div style={{ fontSize: 56, marginBottom: 12 }}>{word.emoji}</div>
              <div style={{ fontSize: 32, fontWeight: 900, color: N, marginBottom: 8, letterSpacing: '-0.02em' }}>{word.en}</div>
              <div style={{ fontSize: 15, color: MU, fontWeight: 500, marginBottom: 20 }}>{word.ipa}</div>
              <span style={{ fontSize: 10, fontWeight: 700, background: '#EEF2F7', color: N, padding: '4px 12px', borderRadius: 99, textTransform: 'uppercase', letterSpacing: '0.08em' }}>
                {word.pos}
              </span>
              <div style={{ marginTop: 24, fontSize: 12, color: '#94A3B8', fontWeight: 500 }}>{t.lesson.tap_flip}</div>
            </div>
          ) : (
            /* Back: translation + definition + example */
            <div style={{ width: '100%' }}>
              <div style={{ textAlign: 'center', marginBottom: 20 }}>
                <div style={{ fontSize: 22, fontWeight: 900, color: N, marginBottom: 4 }}>{word.ru}</div>
                <div style={{ fontSize: 15, color: '#7C3AED', fontWeight: 600 }}>{word.kz}</div>
              </div>
              <div style={{ background: '#F8FBFF', borderRadius: 12, padding: '12px 16px', marginBottom: 12, border: '1px solid rgba(0,56,118,0.07)' }}>
                <div style={{ fontSize: 12, color: '#475569', lineHeight: 1.6 }}>{word.definition}</div>
              </div>
              <div style={{ background: '#F0FDF4', borderRadius: 12, padding: '10px 16px', marginBottom: 12, border: '1px solid #DCFCE7' }}>
                <div style={{ fontSize: 12, color: T, fontStyle: 'italic', lineHeight: 1.6 }}>"{word.example}"</div>
              </div>
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6 }}>
                {word.collocations.map(c => (
                  <span key={c} style={{ fontSize: 11, color: N, background: '#EEF2F7', padding: '3px 10px', borderRadius: 99, fontWeight: 600 }}>{c}</span>
                ))}
              </div>
            </div>
          )}
        </div>

        {/* Action buttons */}
        <div style={{ display: 'flex', gap: 10, marginBottom: 12 }}>
          <button onClick={() => speak(word.en)} style={{
            width: 48, height: 48, borderRadius: 12, border: '1.5px solid rgba(0,56,118,0.15)',
            background: '#fff', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0,
          }}>
            <IcVolume size={20} color={N} />
          </button>

          {flipped && (
            isReviewPhase ? (
              <>
                <button onClick={reviewAgain} style={{
                  flex: 1, padding: '13px', borderRadius: 12, border: '1.5px solid #FECACA',
                  background: '#FEF2F2', color: '#EF4444', fontSize: 13, fontWeight: 700, cursor: 'pointer', fontFamily: 'inherit',
                }}>
                  {t.vocab.hard}
                </button>
                <button onClick={reviewKnown} style={{
                  flex: 1, padding: '13px', borderRadius: 12, border: 'none',
                  background: T, color: '#fff', fontSize: 13, fontWeight: 700, cursor: 'pointer', fontFamily: 'inherit',
                  boxShadow: '0 4px 14px rgba(29,158,117,0.28)',
                }}>
                  {t.vocab.good}
                </button>
              </>
            ) : (
              <>
                <button onClick={markReview} style={{
                  flex: 1, padding: '13px', borderRadius: 12, border: '1.5px solid rgba(239,68,68,0.3)',
                  background: '#FEF2F2', color: '#EF4444', fontSize: 13, fontWeight: 700, cursor: 'pointer', fontFamily: 'inherit',
                }}>
                  {t.vocab.forgot}
                </button>
                <button onClick={markKnown} style={{
                  flex: 1, padding: '13px', borderRadius: 12, border: 'none',
                  background: T, color: '#fff', fontSize: 13, fontWeight: 700, cursor: 'pointer', fontFamily: 'inherit',
                  boxShadow: '0 4px 14px rgba(29,158,117,0.28)',
                }}>
                  {t.vocab.easy}
                </button>
              </>
            )
          )}

          {!flipped && (
            <button onClick={() => setFlipped(true)} style={{
              flex: 1, padding: '13px', borderRadius: 12, border: 'none',
              background: N, color: '#fff', fontSize: 13, fontWeight: 700, cursor: 'pointer', fontFamily: 'inherit',
              boxShadow: '0 4px 14px rgba(0,56,118,0.25)',
            }}>
              {t.vocab.tap_hint}
            </button>
          )}
        </div>

        {/* Word grid progress */}
        <div style={{ display: 'flex', flexWrap: 'wrap', gap: 5, padding: '16px', background: '#fff', borderRadius: 16, border: '1px solid rgba(0,56,118,0.07)' }}>
          {words.map((_, i) => (
            <div key={i} style={{
              width: 28, height: 28, borderRadius: 8, fontSize: 11, fontWeight: 700,
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              background: known.has(i) ? T : review.has(i) ? '#FEF2F2' : i === idx && !isReviewPhase ? N : '#F1F5F9',
              color: known.has(i) || (!isReviewPhase && i === idx) ? '#fff' : review.has(i) ? '#EF4444' : '#94A3B8',
              border: `1px solid ${known.has(i) ? T : review.has(i) ? '#FECACA' : i === idx && !isReviewPhase ? N : 'transparent'}`,
              transition: 'all 0.2s',
            }}>
              {known.has(i) ? <IcCheck size={12} color="#fff" /> : i + 1}
            </div>
          ))}
        </div>
      </div>
    </div>
  )
}
